SELECT COUNT(DISTINCT S.PK_SIAPE) AS TOTAL FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA CH ON CH.SIAPE = S.PK_SIAPE WHERE CH.ANO = 2022 AND CH.SEMESTRE = 1 AND LOWER(CH.SIGLA_CAMPUS) = LOWER('itu') AND LOWER(COALESCE(S.CONTRATO,'')) = 'efetivos' AND LOWER(COALESCE(S.AREA_INGRESSO,S.AREA_INGRESSO_OG,'')) LIKE '%historia%'